-- Create a Function to Calculate Credit Health Score (CHS)
-- -----------------------------------------------------------------------
-- This function computes the composite Credit Health Score (CHS)
-- according to KB "Credit Health Score (CHS)" (KB id:5):
-- Step 1: Define the input parameters.
-- Step 2: Calculate each component using arithmetic and typecasting.
-- Step 3: Sum up the components for the final CHS value.
CREATE OR REPLACE FUNCTION calculate_credit_health_score(
    p_credscore    SMALLINT,
    p_credutil     NUMERIC(5,3),
    p_debincratio  NUMERIC(5,3),
    p_credageyrs   SMALLINT,
    p_delinqcount  SMALLINT,
    p_latepaycount SMALLINT,
    p_choffs       SMALLINT,
    p_bankr        SMALLINT
)
RETURNS NUMERIC(5,3)
LANGUAGE plpgsql
AS $$
DECLARE
    comp1 NUMERIC(5,3);
    comp2 NUMERIC(5,3);
    comp3 NUMERIC(5,3);
    comp4 NUMERIC(5,3);
    comp5 NUMERIC(5,3);
    total NUMERIC(5,3);
BEGIN
    -- Step 1: Compute 0.4 * (credscore/850)
    comp1 := 0.4 * (p_credscore::NUMERIC / 850);
    -- Step 2: Compute 0.2 * (1 - credutil)
    comp2 := 0.2 * (1 - p_credutil);
    -- Step 3: Compute 0.2 * (1 - debincratio)
    comp3 := 0.2 * (1 - p_debincratio);
    -- Step 4: Compute 0.1 * (credageyrs/20)
    comp4 := 0.1 * (p_credageyrs::NUMERIC / 20);
    -- Step 5: Compute 0.1 * (1 - ((delinqcount + latepaycount + choffs + bankr)/10))
    comp5 := 0.1 * (1 - ((p_delinqcount + p_latepaycount + p_choffs + p_bankr)::NUMERIC / 10));
    -- Final CHS computed as the sum of the individual components.
    total := comp1 + comp2 + comp3 + comp4 + comp5;
    RETURN total;
END;
$$;

