CREATE OR REPLACE FUNCTION generate_performance_alert()
RETURNS TRIGGER AS $$
DECLARE
    panel_age DECIMAL;
    expected_performance DECIMAL;
    plant_id UUID;
    alert_count INT;
BEGIN
    SELECT p.hubregistry, EXTRACT(YEAR FROM AGE(NEW.perfmoment, pl.initdate))
    INTO plant_id, panel_age
    FROM panel p
    JOIN plant pl ON p.hubregistry = pl.growregistry
    WHERE p.panemark = NEW.solmodref;

    -- Change degradation rate from 0.7% to 1.0% per year
    expected_performance := 100.0 - (panel_age * 1.0);

    DECLARE
        actual_performance DECIMAL;
        panel_power DECIMAL;
    BEGIN
        SELECT powratew INTO panel_power
        FROM panel
        WHERE panemark = NEW.solmodref;

        actual_performance := (NEW.measpoww / panel_power) * 100;

        -- Change threshold from 80% to 75% of expected value
        IF actual_performance < (expected_performance * 0.75) THEN
            SELECT COUNT(*) INTO alert_count
            FROM alerts
            WHERE deviceref = NEW.solmodref AND alertstat = 'Critical'
            AND alertmoment > CURRENT_DATE - INTERVAL '30 days';

            IF alert_count = 0 THEN
                INSERT INTO alerts (
                    alertreg,
                    compreg,
                    deviceref,
                    incidentref,
                    alertmoment,
                    alertstat,
                    alertcnt,
                    maintprior,
                    replaceprior,
                    optpotential
                ) VALUES (
                    'ALERT_' || substring(md5(random()::text), 1, 10),
                    plant_id,
                    NEW.solmodref,
                    NEW.perfregistry,
                    NEW.perfmoment,
                    'Critical',
                    1,
                    'High',
                    CASE WHEN actual_performance < (expected_performance * 0.55) THEN 'High' ELSE 'Medium' END,
                    'High'
                );
            ELSE
                UPDATE alerts
                SET alertcnt = alertcnt + 1
                WHERE deviceref = NEW.solmodref
                AND alertstat = 'Critical'
                AND alertmoment = (
                    SELECT MAX(alertmoment)
                    FROM alerts
                    WHERE deviceref = NEW.solmodref
                );
            END IF;
        END IF;
    END;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

